library;

// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report.dart';
import 'package:baseball_detector_flutter/data/models/paging_data.dart';
import 'package:baseball_detector_flutter/data/models/resource.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';

part 'session_details_state.freezed.dart';

@freezed
abstract class SessionDetailsState with _$SessionDetailsState {
  const SessionDetailsState._();

  const factory SessionDetailsState({
    required Session session,
    required PagingData<ResourceData> resources,
    AICoachReport? report,
    @Default(null) String? reportError,
  }) = _SessionDetailsState;

  bool get hasReport => session.aiCoachReport?.id != null;

  bool get isReportLoading =>
      hasReport && report == null && reportError == null;

  bool get canShowReport =>
      report != null &&
      report!.status == AICoachReportStatus.completed &&
      report!.content != null;
}

